import os

def delete_user_file(directory, filename):
    """
    Deletes a user's uploaded file from the specified directory.
    
    Args:
        directory (str): The path to the uploads directory where the file is located.
        filename (str): The name of the file to be deleted.
    
    Returns:
        bool: True if the file was successfully deleted, False otherwise.
    """
    try:
        os.remove(os.path.join(directory, filename))
        return True
    except FileNotFoundError:
        print(f"File {filename} not found in the directory.")
        return False